<template>
  <el-submenu v-if="item.children && item.children.length > 0" :index="String(item.id)">
    <template slot="title">{{ item.nameCn }}</template>
    <customer-menu-item v-for="child in item.children" :key="String(child.id)" :item="child" :depth="depth + 1" @select="$emit('select', $event)" />
  </el-submenu>
  <el-menu-item v-else :index="String(item.id)" @click="$emit('select', { id: String(item.id), depth: depth })">
    {{ item.nameCn }}
  </el-menu-item>
</template>

<script>
export default {
  name: 'CustomerMenuItem',
  props: {
    item: {
      type: Object,
      required: true
    },
    depth: {
      type: Number,
      default: 1
    }
  }
};
</script>
